window.__QUIZ_DATA__=[{"id":"objective>Physics>1998>1","subject":"Physics","year":"1998","type":"Objective","topic":"SCALARS AND VECTORS : CONCEPT OF VECTORS","question":"Which of the following pairs of physical quantities comprises vectors?","images":[],"options":{"A":"Capacitance and inductance","B":"Force ratio and velocity ratio","C":"Friction and momentum","D":"Energy and power"},"answer":"C","explanation":"The momentum of a body is a vector quantity, for it is the product of mass, a scalar, by velocity, a vector.    Friction is an opposing force and Force, is a vector quantity, as it has both direction and magnitude.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1998>2","subject":"Physics","year":"1998","type":"Objective","topic":"SPEED AND VELOCITY : CONCEPT OF VELOCITY","question":"During the same time interval, it is observed that a train travels the same distance as does a lorry. The two vehicles therefore have the same","images":[],"options":{"A":"uniform acceleration","B":"instantaneous velocity","C":"average velocity","D":"average speed"},"answer":"D","explanation":"The average speed is the total distance traveled by the object in a particular time interval.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1998>3","subject":"Physics","year":"1998","type":"Objective","topic":"MOTION : SIMPLE IDEAS OF CIRCULAR MOTION","question":"A piece of stone attached to one end of a string is whirled round in a horizontal circle. When the string is suddenly cut, the stone will","images":[],"options":{"A":"move towards the centre of the circle.","B":"stop moving immediately.","C":"move along a circular path of smaller radius.","D":"fly off in a direction tangential to the circular path"},"answer":"D","explanation":"When a stone is going around a circular path, the instantaneous velocity of stone is acting as tangent to the circle. When the string breaks, the centripetal force stops to act. Due to inertia, the stone continues to move along the tangent to circular path. So, the stone flies off tangentially to the circular path.","marks":"1","difficulty":"3"},{"id":"objective>Physics>1998>4","subject":"Physics","year":"1998","type":"Objective","topic":"EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES","question":"The term torque means","images":[],"options":{"A":"the moment of a couple about an axis.","B":"the resultant of several forces acting on a body in equilibrium.","C":"two equal and opposite forces whose lines of action do not coincide.","D":"two coplanar forces at right angles to each other."},"answer":"A","explanation":"Torque is the measure of the force that can cause an object to rotate about an axis. Force is what causes an object to accelerate in linear kinematics. Similarly, torque is what causes an angular acceleration. Hence, torque can be defined as the rotational equivalent of linear force.","marks":"1","difficulty":"3"},{"id":"objective>Physics>1998>5","subject":"Physics","year":"1998","type":"Objective","topic":"FLUID AT REST : VOLUME, DENSITY AND RELATIVE DENSITY","question":"A rectangular block of wood floats in water with two-thirds of its volume immersed. When placed in another liquid, it floats with half of its volume immersed. Calculate the relative density of the liquid.","images":[],"options":{"A":"1.43","B":"1.33","C":"1.00","D":"0.75"},"answer":"D","explanation":"Relativedensity=Volume of liquid displacedVolume of water displaced=1/22/3=12x32=34=0.75","marks":"1","difficulty":"2"},{"id":"objective>Physics>1998>6","subject":"Physics","year":"1998","type":"Objective","topic":"EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES","question":"The diagram beside shows a box X of weight W resting on a plank PQ that has its lower end P hinged to a horizontal floor PR. The plank makes an angle \u03b8 with the floor.   Use this information to answer Questions below     As the end Q of the plank is raised, the component of W, normal to the plank will","images":["data:image/png;base64,"],"options":{"A":"increase","B":"decrease","C":"remain the same","D":"be slightly greater than W"},"answer":"B","explanation":"As the end Q of the plank is raised, the value of \u03b8 increases, and as \u03b8 increases, cos \u03b8 decreases. Therefore, the component of W, normal to the plank will decrease","marks":"1","difficulty":"3"},{"id":"objective>Physics>1998>7","subject":"Physics","year":"1998","type":"Objective","topic":"EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES","question":"The diagram beside shows a box X of weight W resting on a plank PQ that has its lower end P hinged to a horizontal floor PR. The plank makes an angle \u03b8 with the floor.   Use this information to answer Questions below   If \u03b8 is equal to \u03b1 at the time the box is just about to slide down the plank, the coefficient of static friction between the plank and the box is","images":["data:image/png;base64,"],"options":{"A":"sin \u03b1","B":"cos \u03b1","C":"tan \u03b1","D":"sec \u03b1"},"answer":"C","explanation":"F=\u03bcR;\u03bc=FrR;Fr=mgsin\u03b1;R=mgcos\u03b1;\u2234\u03bc=mgsin \u03b1mgcos \u03b1=tan\u03b1","marks":"1","difficulty":"3"},{"id":"objective>Physics>1998>8","subject":"Physics","year":"1998","type":"Objective","topic":"MACHINES :","question":"The diagram beside shows a box X of weight W resting on a plank PQ that has its lower end P hinged to a horizontal floor PR. The plank makes an angle \u03b8 with the floor.   Use this information to answer Questions below   If the box is pulled up from P to Q, which of the following expresses the velocity ratio of the inclined plane?","images":["data:image/png;base64,"],"options":{"A":"PRPQ","B":"QRPQ","C":"QRPR","D":"PQQR"},"answer":"D","explanation":"V.R=Distance moved by effortDistance moved by load=PQQR","marks":"1","difficulty":"3"},{"id":"objective>Physics>1998>9","subject":"Physics","year":"1998","type":"Objective","topic":"FLUID AT REST : PRESSURE IN FLUIDS","question":"A pilot records the atmospheric pressure outside his plane as 63 cm of Hg while a ground observer records a reading of 75 cm of Hg with his barometer. Assuming that the density of air is constant, calculate the height of the plane above the ground.  [Take the relative densities of air and mercury as 0.00136 and 13.6 respectively.]","images":[],"options":{"A":"120 m","B":"138 m","C":"274 m","D":"1,200 m"},"answer":"D","explanation":"Let h be the height above the ground;   Pressure change in air = Pressure change in mercury   ==> \u03c1gh = \u03c1gH  \u03c1 = density of mercury; g = gravitational force; H = change in height  ==> \u03c1gh = 0.00136 x g x h = (75 - 63) x 13.6 x g  \u2234h=12 x 13.60.00136=120,000cm=1,200 m","marks":"1","difficulty":"3"},{"id":"objective>Physics>1998>10","subject":"Physics","year":"1998","type":"Objective","topic":"PROJECTILE MOTION :","question":"An object is projected with a velocity of 100 ms-1 at an angle of 60o to the vertical. Calculate the time taken by the object to reach the highest point.  [Take g as 10 ms-2]","images":[],"options":{"A":"5.0 s","B":"8.7 s","C":"10.0 s","D":"17.3 s"},"answer":"B","explanation":"vo = 100 ms-1; \u03b8 = 60o; At greatest height v = 0;  vosin \u03b8 - gt = 0; vosin \u03b8 = gt  t=vosin \u03b8g=100sin 60o10=10x\u221a32=5\u221a3=5x1.732=8.7s","marks":"1","difficulty":"2"},{"id":"objective>Physics>1998>11","subject":"Physics","year":"1998","type":"Objective","topic":"GRAVITATIONAL FIELD : ACCELERATION DUE TO GRAVITY","question":"The earth is not a perfect sphere because its equatorial axis is longer than the polar axis. Where on the earth's surface would an object have its greatest weight?","images":[],"options":{"A":"Halfway between the equator and the north pole","B":"Near the equator","C":"Halfway between the equator and the south pole","D":"At either pole"},"answer":"D","explanation":"The Earth's equatorial bulge (itself also caused by centrifugal force from rotation) causes objects at the Equator to be further from the planet's center than objects at the poles. Because the force due to gravitational attraction between two bodies (the Earth and the object being weighed) varies inversely with the square of the distance between them,  an object at the Equator experiences a weaker gravitational pull than an object on one of the poles.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1998>12","subject":"Physics","year":"1998","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"A ball of mass 5.0 kg hits a smooth vertical wall normally with a speed of 2 ms-1 and rebounds with the same speed. The determine the impulse experienced by the ball.","images":[],"options":{"A":"20.0 kgms-1","B":"10.0 kgms-1","C":"5.0 kgms-1","D":"0.0 kgms-1"},"answer":"A","explanation":"impulse of force = Ft = change in momentum = m(v -u) = mv - mu  since u = v and v moves in opposite direction to u \u2234 u = -v  impulse = mv - m(-v) = mv + mv = 2mv = 2 x 5 x 2 = 20.0 kgms-1","marks":"1","difficulty":"2"},{"id":"objective>Physics>1998>13","subject":"Physics","year":"1998","type":"Objective","topic":"HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT","question":"An object is heated from 30oC to 57oC. The increase in its temperature on Kelvin scale is","images":[],"options":{"A":"17 K","B":"27 K","C":"81 K","D":"300 K"},"answer":"D","explanation":"Increase in temperature = \u03b82 - \u03b81; \u03b81 = initial temperature = 30oC; \u03b82 = final temperature = 57oC  \u0394\u03b8 = 57oC - 30oC = 27oC  \u2234 \u0394\u03b8 = 27 + 273 = 300 K","marks":"1","difficulty":"1"},{"id":"objective>Physics>1998>14","subject":"Physics","year":"1998","type":"Objective","topic":"HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT","question":"The lower and upper fixed points of a mercury-in-glass thermometer are marked Y and 180 mm respectively. On a particular day the mercury meniscus in the thermometer rises to 45 mm. If the corresponding reading on a Celsius scale is 10oC. Calculate the value of Y.","images":[],"options":{"A":"4 mm","B":"18 mm","C":"30 mm","D":"135 mm"},"answer":"C","explanation":"45 - y180 - y=10 - 0100 - 0  45 - y180 - y=10100=110  ==>10(45-y)=180-y  450-10y=180-y  450-180=10y-y  270=9y  \u2234y=2709=30mm","marks":"1","difficulty":"2"},{"id":"objective>Physics>1998>15","subject":"Physics","year":"1998","type":"Objective","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"A piece of brass of mass 170 kg has its temperature raised from 0oC to 30oC. Calculate its increase in volume, given the density of brass at 0oC as 8.5 x 103 kgm-3 and its cubic expansivity as 5.7 x 10-5 K-1.","images":[],"options":{"A":"3.4 x 10-5 m3","B":"4.3 x 10-5 m3","C":"3.4 x 10-4 m3","D":"3.4 x 10-3 m3"},"answer":"A","explanation":"\u03b3=\u0394VV\u0394\u03b8  \u03b3=cubicexpansivity;\u0394V=increaseinvolume;V=originalvolume;\u0394\u03b8=temperaturerise  =>5.7x10-5=\u0394VV x (30 - 0);butV=m\u03c1;m=mass;\u03c1=density=>V=1708.5x103=0.02m3  \u22345.7x10-5=\u0394V0.02 x 30;\u0394V=5.7x10-5x0.6=3.4x10-5m3","marks":"1","difficulty":"3"},{"id":"objective>Physics>1998>16","subject":"Physics","year":"1998","type":"Objective","topic":"CONCEPTS OF MATTER : CONCEPTS OF MATTER","question":"The average kinetic energy of the molecules of a perfect gas is directly proportional to the","images":[],"options":{"A":"pressure exerted by the gas.","B":"volume of the gas molecules.","C":"Kelvin temperature of the gas.","D":"Celsius temperature of the gas."},"answer":"C","explanation":"The average kinetic energy of the molecules of a perfect gas is directly proportional to the Kelvin temperature of the gas. This is a consequence of the kinetic theory of gases, which states that the average kinetic energy of the gas molecules is proportional to the absolute temperature (measured in Kelvin). This is not related to the pressure exerted by the gas, the volume of the gas molecules, or the Celsius temperature of the gas.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1998>17","subject":"Physics","year":"1998","type":"Objective","topic":"HEAT ENERGY : SPECIFIC HEAT CAPACITY","question":"How much heat is emitted when a body of mass 200 g cools from 37oC to 31oC?  [Specific heat capacity of the body = 0.4 Jg-1K-1]","images":[],"options":{"A":"4800 J","B":"1200 J","C":"480 J","D":"202 J"},"answer":"C","explanation":"Heat emitted = mc\u0394\u03b8; m = mass; c = specific heat capacity of the body; \u0394\u03b8 = temperature change  H = 200 x 0.4 x (37 - 31) = 200 x 0.4 x 6 = 480 J","marks":"1","difficulty":"2"},{"id":"objective>Physics>1998>18","subject":"Physics","year":"1998","type":"Objective","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"If the cubic expansivity of brass between 27oC and 100oC is 5.7 x 10-5 K-1, what is its linear expansivity?","images":[],"options":{"A":"2.85 x 10-5 K-1","B":"1.90 x 10-5 K-1","C":"1.86 x 10-5 K-1","D":"1.70 x 10-5 K-1"},"answer":"B","explanation":"\u03b1=\u03b33=5.7 x 10-53=1.90x10-5K-1","marks":"1","difficulty":"2"},{"id":"objective>Physics>1998>19","subject":"Physics","year":"1998","type":"Objective","topic":"HEAT ENERGY : GAS LAWS","question":"Air at temperature 527oC and pressure 30 atmospheres is admitted into the cylinder of an engine. Calculate the pressure of the gas when it has expanded to 5 times its volume and cooled to 127oC as it leaves the engine.","images":[],"options":{"A":"1.5 atmospheres","B":"2.5 atmospheres","C":"3.0 atmospheres","D":"12.8 atmospheres"},"answer":"C","explanation":"P1V1T1=P2V2T2;P2=P1V1T2T1V2  P1=30atm;V1=Vcm3;T1=527+273=800K;T2=127+273=400K;  V2=5V1=5Vcm3  \u2234P2=30 x V x 400800 x 5V=15V5V=3.0atmospheres","marks":"1","difficulty":"3"},{"id":"objective>Physics>1998>20","subject":"Physics","year":"1998","type":"Objective","topic":"HEAT ENERGY : HEAT TRANSFER","question":"The inside of a vacuum flask is usually coated with silver to reduce heat loss by","images":[],"options":{"A":"evaporation","B":"condensation","C":"radiation","D":"conduction"},"answer":"C","explanation":"It is found that, for a given temperature, a dull black surface radiates most and a highly polished surface radiates least. So, silver being a highly polished surface, prevents heat loss by radiation.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1998>21","subject":"Physics","year":"1998","type":"Objective","topic":"HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT","question":"Dry oxygen is trapped by a pellet of mercury in a uniform capillary tube which is sealed at one end. The length of the column of oxygen at 27oC is 50 cm. If the pressure of the oxygen is constant, at what temperature will it length be 60 cm?","images":[],"options":{"A":"360.0oC","B":"240.6oC","C":"237.0oC","D":"87.0oC"},"answer":"D","explanation":"V1T1=V2T2;T1V2=V1T2;T1=V1T2V2  T1=60 x (273 + 27)50=60 x 30050=360K  \u2234T1=360-273=87.0oC","marks":"1","difficulty":"3"},{"id":"objective>Physics>1998>22","subject":"Physics","year":"1998","type":"Objective","topic":"WORK, ENERGY AND POWER : CONCEPT OF ENERGY","question":"A waterfall is 1,260 m high. Calculate the change in temperature of a quantity of water that falls from the top to the bottom of the waterfall.  [Neglect heat loses to the sorroundings, take g as 10 ms-2 and specific heat capacity of water as 4200 Jkg-K-1]","images":[],"options":{"A":"0.3oC","B":"3.0oC","C":"33.3oC","D":"42.0oC"},"answer":"B","explanation":"Heat energy = Potential energy  i.e mc\u0394\u03b8 = mgh ==> c\u0394\u03b8 = gh  \u2234\u0394\u03b8=ghc=10 x 12604200=3.0oC","marks":"1","difficulty":"2"},{"id":"objective>Physics>1998>23","subject":"Physics","year":"1998","type":"Objective","topic":"HEAT ENERGY : BOILING POINT","question":"When a piece of metal is heated until it becomes red-hot. It is then quickly transferred into a beaker containing boiling water. What effect would this have on the boiling water?","images":[],"options":{"A":"The boiling point rises slightly.","B":"The boiling point rises sharply.","C":"The rate of vaporisation of the boiling water increases.","D":"The boiling point first rises and then falls"},"answer":"C","explanation":"Iron is \"red hot\" at 700\u00b0C; boiling water is 100\u00b0C. The heat from the iron will be absorbed by the water which will undergo a phase change to steam. The temperature of the iron will drop until it is in equilibrium with the water-100oC. The water will not get hotter, but it will produce more steam.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1998>24","subject":"Physics","year":"1998","type":"Objective","topic":"HEAT ENERGY : SPECIFIC LATENT HEAT OF FUSION","question":"A 90-W immersion heater is used to supply energy for 5 minutes. The energy supplied is used to completely melt 180 g of a solid at its melting point. Neglecting energy loses to the surroundings, calculate the specific latent heat of fusion of the solid.","images":[],"options":{"A":"0.5 Jg-1","B":"2.5 Jg-1","C":"15.0 Jg-1","D":"150.0 Jg-1"},"answer":"D","explanation":"Powerxtime=mL;m=mass=180g;t=time=5x60=300s;L=latentheat  L=Ptm=90 x 300180=3002=150.0Jg-1","marks":"1","difficulty":"3"},{"id":"objective>Physics>1998>25","subject":"Physics","year":"1998","type":"Objective","topic":"ELECTRIC FIELD : PRODUCTION OF ELECTRIC CHARGES","question":"If an ebonite rod is rubbed with fur","images":[],"options":{"A":"both the ebonite rod and fur will be negatively charged.","B":"the ebonite rod will be positively charged while the fur will have no charge.","C":"there will be electron transfer only if the ebonite rod is earthed.","D":"the ebonite rod will be negatively charged while the fur will be positively charged."},"answer":"D","explanation":"When an ebonite rod is rubbed with fur the rod gets negatively charged because the friction between the fur and the rod makes the ebonite rod to gain an electron from the fur. This is because electrons in fur are less tightly bound than the electrons in the ebonite rod. Therefore, the ebonite rod becomes negatively charged and the fur becomes positively charge due to loss of electron.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1998>26","subject":"Physics","year":"1998","type":"Objective","topic":"ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM","question":"An eclipse of the sun by the moon occurs when the sun, the moon and the earth are all in a straight line and the","images":[],"options":{"A":"earth casts a shadow on the moon.","B":"moon casts a shadow on the sun.","C":"moon is between the sun and the earth.","D":"sun is between the moon and the earth."},"answer":"C","explanation":"An eclipse of the Sun happens when the Moon moves between the Sun and Earth, blocking out the Sun's rays and casting a shadow on parts of Earth.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1998>27","subject":"Physics","year":"1998","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"The phenomenon which occurs when light changes direction as it passes from one medium to another is called","images":[],"options":{"A":"reflection","B":"polarisation","C":"interference","D":"refraction"},"answer":"D","explanation":"Refraction of light is the phenomenon of bending of light or change in the direction of light, when it passes obliquely from one transparent medium to another.  During refraction the frequency of the refracted ray remains constant; though speed of light changes on refraction.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1998>28","subject":"Physics","year":"1998","type":"Objective","topic":"LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS","question":"What is the image distance of an object placed at a distance of 2f from a converging lens of focal length f?","images":[],"options":{"A":"f4","B":"f2","C":"f","D":"2f"},"answer":"D","explanation":"The image distance of an object placed at a distance of 2f from a converging lens of focal length f is 2f.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1998>29","subject":"Physics","year":"1998","type":"Objective","topic":"LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS","question":"A converging lens of focal length 5 cm is used as a magnifying glass by a man whose near-point is 35 cm. Calculate the magnification given by the lens.","images":[],"options":{"A":"8","B":"7","C":"6","D":"5"},"answer":"C","explanation":"M=vu;v=35cm;f=5cm;u=?;but1f=1u+1v==>1u=1f-1v  1u=15-135=7 - 135  1u=635  \u2234u=356=55/6cm  \u2234M=3535/6=35x635=6","marks":"1","difficulty":"3"},{"id":"objective>Physics>1998>30","subject":"Physics","year":"1998","type":"Objective","topic":"LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS","question":"The images formed by diverging lenses are always","images":[],"options":{"A":"diminished, virtual and inverted.","B":"diminished, virtual and erect.","C":"diminished, inverted and real.","D":"magnified, virtual and erect."},"answer":"B","explanation":"The image is always virtual, diminished, erect and is located between the object and the lens.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1998>31","subject":"Physics","year":"1998","type":"Objective","topic":"LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS","question":"An astronomical telescope, having an objective of focal length 100 cm and an eyepiece of focal length 10 cm, is used in normal adjustment. Calculate the separation of the lenses.","images":[],"options":{"A":"0.10 m","B":"0.90 m","C":"1.10 m","D":"1.80 m"},"answer":"C","explanation":"In normal adjustments, the seperation of lenses = fo + fe; where fo = 100 cm = 1 m; fe = 10 cm = 0.1 m  \u2234 seperation = 1 + 0.1 = 1.10 m","marks":"1","difficulty":"2"},{"id":"objective>Physics>1998>32","subject":"Physics","year":"1998","type":"Objective","topic":"LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS","question":"A lantern gives an image 3 m square of a slide 7.62 cm square on a screen. If the screen is 10 m from the projection lens of the lantern, calculate the focal length of the lens.","images":[],"options":{"A":"40.3 cm","B":"26.1 cm","C":"24.8 cm","D":"0.7 cm"},"answer":"C","explanation":"Heightofimage=3m=300cm;Heightofobject=7.63cm;  Imagedistance=10m=1000cm  M=Height of imageHeight of object=3007.62=39.37  alsoM=Image distance (v)Object distance (u)i.eM=vu==>u=vM=100039.37=25.4cm  but1f=1u+1v  1f=125.4+11000=1000 + 25.425400  1f=1025.425400  \u2234f=254001025.4=24.8cm","marks":"1","difficulty":"3"},{"id":"objective>Physics>1998>33","subject":"Physics","year":"1998","type":"Objective","topic":"LIGHT WAVES : SOURCES OF LIGHT","question":"The intensity of light falling on the film in a camera depends on the  I. brightness of the object.  II. diameter of the aperture stop.  III. speed of the shutter.  Which of the statements above is/are correct?","images":[],"options":{"A":"I, II and III","B":"I and II only","C":"I and III only","D":"III only"},"answer":"A","explanation":"The intensity of light falling on the film in a camera does depend on the brightness of the object, the diameter of the aperture stop, and the speed of the shutter. Therefore, all three statements are correct.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1998>34","subject":"Physics","year":"1998","type":"Objective","topic":"SOUND WAVES : SPEED OF SOUND","question":"The shortest length of the air column in a resonance tube at resonance is 0.12 m and the next resonant length is 0.37 m. Calculate the frequency of vibration given that the speed of sound in air is 340 ms-1.","images":[],"options":{"A":"1360 Hz","B":"694 Hz","C":"680 Hz","D":"347 Hz"},"answer":"C","explanation":"v=f\u03bb=2f(L2-L1)\u2234f=v2f(L2 - L1)=3402(0.37 - 0.12)=3400.5=680Hz","marks":"1","difficulty":"3"},{"id":"objective>Physics>1998>35","subject":"Physics","year":"1998","type":"Objective","topic":"SOUND WAVES : VIBRATION IN STRINGS","question":"A sonometer wire under a tension of 10 N, produces a frequency of 250 Hz when plucked. Keeping the length of the wire constant, the tension is adjusted to produce a new frequency of 350 Hz. Calculate the new tension.","images":[],"options":{"A":"39.2 N","B":"19.6 N","C":"14.2 N","D":"7.4 N"},"answer":"B","explanation":"f\u03b1\u221aTf=k\u221aTwherekisconstant==>k=f\u221aT  f1\u221aT1=f2\u221aT2==>f1f2=\u221aT1\u221aT2  ==>250350=\u221a10\u221aT2  =57=\u221a10\u221aT2  =5\u221aT2=7\u221a10  =\u221aT2=7\u221a105  squarebothsides  \u2234T2=49 x 1025=49025=19.6N","marks":"1","difficulty":"3"},{"id":"objective>Physics>1998>36","subject":"Physics","year":"1998","type":"Objective","topic":"SOUND WAVES : VIBRATION OF AIR IN PIPE \u2013 OPEN AND CLOSED PIPES","question":"Which of the following instruments produces sound by the vibration of air column?","images":[],"options":{"A":"Drum","B":"Violin","C":"Guitar","D":"Flute"},"answer":"D","explanation":"Flute players can change the pitch by changing the length of the tube (air column) with the fingers or by increasing the air speed in order to force the sound waves to the next note in the harmonic overtone series.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1998>37","subject":"Physics","year":"1998","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(\ud835\udecc), PERIOD (T) AND VELOCITY (V)","question":"Calculate the wavelength of a note which is one octave lower than a note of 256 Hz in a medium in which the speed of sound is 352 ms1","images":[],"options":{"A":"0.69 m","B":"1.38 m","C":"2.75 m","D":"5.50 m"},"answer":"C","explanation":"fc = 256 Hz; an octave lower f = 2562 = 128 Hz; v=f\u03bb;\u03bb=vf=352128=2.75m","marks":"1","difficulty":"3"},{"id":"objective>Physics>1998>38","subject":"Physics","year":"1998","type":"Objective","topic":"TYPES OF WAVES : TRANSVERSE AND LONGITUDINAL","question":"Which of the following are both mechanical and transverse?","images":[],"options":{"A":"Infra-red rays","B":"Gamma rays","C":"Sound waves","D":"Water waves"},"answer":"D","explanation":"Water waves are both mechanical and transverse because it requires a material medium (water) and its vibrations move perpendicular to the direction of the wave.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1998>39","subject":"Physics","year":"1998","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"An electromagnetic wave of frequency 5.0 x 1014 Hz, is incident on the surface of water of refractive index. Taking the speed of the wave in air as 3 x 108 ms-1, calculate the wavelength of the wave in water.","images":[],"options":{"A":"2.2 x 10-6 m","B":"1.7 x 10-6 m","C":"8.0 x 10-7 m","D":"4.5 x 10-7 m"},"answer":"D","explanation":"anw=\u03bba\u03bbw=43==>\u03bbw=3\u03bba4  Fromv=f\u03bba;\u03bba=vf=3.0 x 1085.0 x 1014=35x108 - 14=0.6x10-6=6.0x10-7m  \u2234\u03bbw=3 x 6.0 x 10-74=18.0 x 10-74=4.5x10-7m","marks":"1","difficulty":"3"},{"id":"objective>Physics>1998>40","subject":"Physics","year":"1998","type":"Objective","topic":"GRAVITATIONAL FIELD : ACCELERATION DUE TO GRAVITY","question":"The gravitational force of the moon is one-sixth that of the earth. If the body weighs 6.0 N on the moon, calculate its weight on the earth.","images":[],"options":{"A":"36.0 N","B":"12.0 N","C":"6.0 N","D":"2.0 N"},"answer":"A","explanation":"The weight of an object is the force of gravity on it. Since the gravitational force of the moon is one-sixth that of the earth, the weight of the body on earth would be six times its weight on the moon. Therefore, if the body weighs 6.0 N on the moon, it would weigh 6.0 N * 6 = 36.0 N on the earth.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1998>41","subject":"Physics","year":"1998","type":"Objective","topic":"MAGNETIC FIELD : MAGNETIZATION AND DEMAGNETIZATION","question":"In the electrical method of magnetisation, the polarity of the magnet depends on the","images":[],"options":{"A":"amount of current passed.","B":"direction of current.","C":"magnetic material used.","D":"size of the magnetic material."},"answer":"B","explanation":"In the electrical method of magnetisation, the polarity of the magnet depends on the direction of the current. This is because the direction of the magnetic field produced by a current-carrying wire is determined by the right-hand rule, which states that if you point the thumb of your right hand in the direction of the current, your fingers will curl in the direction of the magnetic field.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1998>42","subject":"Physics","year":"1998","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE","question":"A cell of e.m.f. 1.5 V is connected in series with a resistor of resistance 3 \u03a9. A high resistance voltmeter connected across the cell registers only 0.9 V. Calculate the internal resistance of the cell.","images":[],"options":{"A":"5.0 \u03a9","B":"4.5 \u03a9","C":"2.4 \u03a9","D":"2.0 \u03a9"},"answer":"D","explanation":"V=IR==>I=VR=0.93=0.3A  E=I(R+r)=IR+Ir  E-IR=Ir  E - IRI=r  sinceV=IR  \u2234r=E - VI=1.5 - 0.90.3=0.60.3=2.0\u03a9","marks":"1","difficulty":"3"},{"id":"objective>Physics>1998>43","subject":"Physics","year":"1998","type":"Objective","topic":"ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY","question":"Calculate the resistance of the filament of a lamp rated at 240 V, 60 W.","images":[],"options":{"A":"240 \u03a9","B":"360 \u03a9","C":"960 \u03a9","D":"1440 \u03a9"},"answer":"C","explanation":"P=V2R==>R=V2P=240260=57,60060=960\u03a9","marks":"1","difficulty":"3"},{"id":"objective>Physics>1998>44","subject":"Physics","year":"1998","type":"Objective","topic":"MAGNETIC FIELD : THE EARTH\u2019S MAGNETIC FIELD","question":"The diagram below illustrates a freely suspended bar magnet hanging from a point in a horizontal ceiling. The thread used for suspending the magnet and the axis of the magnet are as indicated on the diagram. The angle marked \u03b8 is called the angle of","images":["data:image/png;base64,"],"options":{"A":"depression","B":"declination","C":"variation","D":"dip"},"answer":"D","explanation":"Magnetic dip, dip angle, or magnetic inclination is the angle made with the horizontal by the Earth's magnetic field lines. The dip angle is in principle the angle made by the needle of a vertically held compass","marks":"1","difficulty":"2"},{"id":"objective>Physics>1998>45","subject":"Physics","year":"1998","type":"Objective","topic":"ELECTROMAGNETIC FIELD : LENZ\u2019S LAW","question":"Lenz's law of electromagnetic induction states that","images":[],"options":{"A":"the induced charge is constant for a fixed change of flux.","B":"a force is exerted on a current-carrying conductor in a magnetic field.","C":"the magnitude of the induced e.m.f. in a circuit is proportional to the rate of change of the number of lines of force linking the circuit.","D":"the induced current in a conductor is in such a direction as to oppose the change producing it."},"answer":"D","explanation":"Lenz's law, in electromagnetism, states that an induced electric current flows in a direction such that the current opposes the change that induced it. This law was deduced in 1834 by the Russian physicist Heinrich Friedrich Emil Lenz (1804\u201365).","marks":"1","difficulty":"2"},{"id":"objective>Physics>1998>46","subject":"Physics","year":"1998","type":"Objective","topic":"MAGNETIC FIELD : MAGNETIC FORCE ON A MOVING CHARGED PARTICLE","question":"A proton of charge 1.6 x 10-19 C is projected into a uniform magnetic field of flux density 5.0 x 10-5 T. If the proton moves parallel to the field with a constant speed of 1.6 x 106 ms-1, calculate the magnitude of the force exerted on it by the field.","images":[],"options":{"A":"0.0 N","B":"2.0 x 10-21 N","C":"1.3 x 10-17 N","D":"5.1 x 10-14 N"},"answer":"C","explanation":"F = Bqv; F = force; B = flux density; q = charge; v = velocity  ==> F = 5.0 x 10-5 x 1.6 x 10-19 x 1.6 x 106 = 1.3 x 10-17 N","marks":"1","difficulty":"3"},{"id":"objective>Physics>1998>47","subject":"Physics","year":"1998","type":"Objective","topic":"MAGNETIC FIELD : CONCEPT OF MAGNETIC FIELD","question":"The direction of the magnetic field at a point in the vicinity of a bar magnet is","images":[],"options":{"A":"along the line joining the point to a neutral point.","B":"always away from the south pole of the magnet.","C":"opposite the direction of the resultant field at that point.","D":"the direction towards which the north pole of a compass needle would point."},"answer":"D","explanation":"The direction of the magnetic field at a point in the vicinity of a bar magnet is the direction towards which the north pole of a compass needle would point.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1998>48","subject":"Physics","year":"1998","type":"Objective","topic":"ELECTROMAGNETIC FIELD : RESONANCE","question":"In L-C circuit, the inductance and capacitance are 0.5 H and 20 \u03bcf respectively. Calculate the resonant frequency of the circuit.","images":[],"options":{"A":"24.2 Hz","B":"36.7 Hz","C":"50.3 Hz","D":"60.5 Hz"},"answer":"C","explanation":"fo=12\u03c0\u221aLC=12\u03c0\u221a(0.5 x 20 x 10-6)=16.286\u221a10-5  ==>fo=16.286 x 3.2 x 10-3=10.01988  \u2234fo=50.3Hz","marks":"1","difficulty":"3"},{"id":"objective>Physics>1998>49","subject":"Physics","year":"1998","type":"Objective","topic":"SIMPLE A.C. CIRCUITS : POWER","question":"The diagram below illustrates an a.c. source of 50 V(r.m.s), 100/\u03c0 Hz connected in series with an inductor of inductance L and a resistor of resistance R. The current in the circuit is 2 A and the p.d across L and R are 30 V and 40 V respectively.     Use this information to answer Questions below     Calculate the power factor of the circuit.","images":["data:image/png;base64,"],"options":{"A":"1.33","B":"1.25","C":"0.80","D":"0.75"},"answer":"C","explanation":"Powerfactor=cos\u03b8=RZ;whereR=VI=402=20\u03a9  Z=\u221a(R2+X2)=\u221a(202+152)=\u221a(400+225)  ==>Z=\u221a625=25\u03a9  \u2234cos\u03b8=2025=0.8","marks":"1","difficulty":"3"},{"id":"objective>Physics>1998>50","subject":"Physics","year":"1998","type":"Objective","topic":"SIMPLE A.C. CIRCUITS : POWER","question":"The diagram below illustrates an a.c. source of 50 V(r.m.s), 100/\u03c0 Hz connected in series with an inductor of inductance L and a resistor of resistance R. The current in the circuit is 2 A and the p.d across L and R are 30 V and 40 V respectively.     Use this information to answer Questions below   Calculate the average power dissipated in the circuit.","images":["data:image/png;base64,"],"options":{"A":"100 W","B":"80 W","C":"60 W","D":"20 W"},"answer":"B","explanation":"I = 2 A, R = 20 &#937;  P = I2R = 22 x 20 = 4 x 20 = 80 W","marks":"1","difficulty":"3"},{"id":"objective>Physics>1998>51","subject":"Physics","year":"1998","type":"Objective","topic":"HOOKE\u2019S LAW, YOUNG\u2019S MODULES AND WORK DONE IN SPRINGS AND STRING :","question":"Use the following data to determine the length L of a wire when a force of 30 N is applied, assuming Hooke's law is obeyed.  Force applied/N 0 5 10 30Length of wire/mm 500.0 500.5 501.0 L","images":[],"options":{"A":"3.0 mm","B":"3.5 mm","C":"503.0 mm","D":"503.5 mm"},"answer":"C","explanation":"F\u03b1e;f=ke;k=fe  WhenF=0;L=500.0mmi.ewhennoforceisapplied,theoriginallengthis500.0mm  WhenF=5N;Newlength=500.5\u2234e=500.5-500=0.5mm  Fromk=fe=50.5=10Nm-1  NowwhenF=30;e=Fk=3010=3.0mm  \u2234L=500.0+3.0=503.0mm","marks":"1","difficulty":"2"},{"id":"objective>Physics>1998>52","subject":"Physics","year":"1998","type":"Objective","topic":"FLUID AT REST : PRESSURE IN FLUIDS","question":"Which of the following explains the concave meniscus of water in a clean glass tube? The","images":[],"options":{"A":"adhesion between water and glass molecules is greater than the cohesion between water molecules.","B":"cohesion between water molecules is greater than the adhesion between glass and water molecules.","C":"molecules of water near the glass move faster than the molecules at the centre of the tube.","D":"molecules of water at the water-air boundary are often attracted to the centre of the tube."},"answer":"A","explanation":"Water forms concave meniscus in a clean glass tube because the force of attraction between the water and glass molecules is stronger than the force of attraction between the water molecules.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1998>53","subject":"Physics","year":"1998","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC ENERGY AND POWER","question":"An electron is accelerated from rest through a potential difference of 70 kV in a vacuum. Calculate the maximum speed acquired by the electron.  [electronic charge = -1.6 x 10-19 C; mass of an electron = 9.1 x 10-31 kg]","images":[],"options":{"A":"3.00 x 108 ms-1","B":"2.46 x 108 ms-1","C":"1.57 x 108 ms-1","D":"1.32 x 108 ms-1"},"answer":"C","explanation":"eV=12mv2;2eV=mv2;v2=2eVm  ==>v=\u221a2eVm=\u221a2 x 1.6 x 10-19 x 70 x 1039.1 x 10-31=\u221a224 x 10-169.1 x 10-31  =v=\u221a24.620x1015  \u2234v=1.57x108ms-1","marks":"1","difficulty":"3"},{"id":"objective>Physics>1998>54","subject":"Physics","year":"1998","type":"Objective","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"When light from a source is sent through a gas  I. certain wavelengths are absorbed.  II. an emission line spectrum results.  III. a dark line is left.  Which of the following is/are correct?","images":[],"options":{"A":"I only","B":"III only","C":"I and II only","D":"I and III only"},"answer":"D","explanation":"When light from a source is sent through a gas some light of certain wavelengths are absorbed resulting in gaps that appear as dark lines","marks":"1","difficulty":"2"},{"id":"objective>Physics>1998>55","subject":"Physics","year":"1998","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"Calculate the value of half-life of a radioactive element whose decay constant is 0.077 s-1.","images":[],"options":{"A":"0.5 s","B":"3.0 s","C":"5.1 s","D":"9.0 s"},"answer":"D","explanation":"t1/2=0.693\u03bb=0.6930.077=9.0s","marks":"1","difficulty":"2"},{"id":"objective>Physics>1998>56","subject":"Physics","year":"1998","type":"Objective","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"The process of increasing the energy of an atom via inelastic collision with an electron is known as","images":[],"options":{"A":"ionization","B":"excitation","C":"field emission","D":"photoemission"},"answer":"B","explanation":"excitation, is the addition of a discrete amount of energy (called excitation energy) to a system\u2014such as an atomic nucleus, an atom, or a molecule\u2014that results in its alteration, ordinarily from the condition of lowest energy (ground state) to one of higher energy (excited state).","marks":"1","difficulty":"2"},{"id":"objective>Physics>1998>57","subject":"Physics","year":"1998","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"A radioactive nuclide of proton number X emits a \u03b2 particle to form a new nuclide of proton number Y. The correct equation relating X and Y is","images":[],"options":{"A":"X = Y - 1","B":"X = Y + 1","C":"X = 1 - Y","D":"X = 1/Y"},"answer":"B","explanation":"When a radioactive nuclide emits a \u03b2 particle (which is essentially an electron), a neutron in the nucleus is converted into a proton. This increases the proton number by 1. Therefore, the correct equation relating X and Y is X = Y + 1.","marks":"1","difficulty":"3"},{"id":"objective>Physics>1998>58","subject":"Physics","year":"1998","type":"Objective","topic":"MOTION : VISCOSITY (FRICTION IN FLUIDS)","question":"The frictional effect between the layers of a moving fluid is called","images":[],"options":{"A":"capillarity","B":"turbulence","C":"diffusion","D":"viscosity"},"answer":"D","explanation":"Viscosity is the resistance of a fluid (liquid or gas) to a change in shape or movement of neighbouring portions relative to one another. Viscosity is a measure of a fluid's resistance to flow. It describes the internal friction of a moving fluid.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1998>59","subject":"Physics","year":"1998","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"Two radioactive elements X and Y have half-lives of 100 and 50 years respectively. Samples of X and Y initially contain equal number of atoms. What is the ratio of the number of the remaining atoms of X to that of Y after 200 years?","images":[],"options":{"A":"4 : 1","B":"1 : 2","C":"1 : 1","D":"1 : 4"},"answer":"D","explanation":"X\u21d2Initialamountofsamplex  Halflife=50years  After200yearsi.e.,4halflives,amount remaining=124=116  Y\u21d2Initialamountofsampley  Halflife= 100years  After200yearsi.e.,2halflives,amount remaining=122=14  So,ratioofXremainingtothatofY=116:14=116x41=14=1:4","marks":"1","difficulty":"3"},{"id":"objective>Physics>1998>60","subject":"Physics","year":"1998","type":"Objective","topic":"WAVE-PARTICLE PARADOX : DUALITY OF MATTER","question":"It is always not possible to determine exactly and simultaneously the position and momentum of a particle. This statement is known as the","images":[],"options":{"A":"De Broglie law.","B":"Heisenberg uncertainty principle.","C":"Compton effect.","D":"Frank-Hertz experimental law."},"answer":"B","explanation":"Formulated by the German physicist and Nobel laureate Werner Heisenberg in 1927, the uncertainty principle states that we cannot know both the position and momentum of a particle, such as a photon or electron, with perfect accuracy; the more we know about the particle's position, the less we know about its momentum and vice versa.","marks":"1","difficulty":"3"}];